import{_ as a,o as r,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const w=JSON.parse('{"title":"41B. Hyperbaric Allowance","description":"","frontmatter":{"title":"41B. Hyperbaric Allowance","eba":"Nurses and Midwives 2024-2028","topics":["leave","hours","shift-work","overtime"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/41B-hyperbaric-allowance.md","filePath":"ebas/nurses-midwives/allowances/41B-hyperbaric-allowance.md"}'),s={name:"ebas/nurses-midwives/allowances/41B-hyperbaric-allowance.md"};function i(t,e,l,c,p,d){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_41b-hyperbaric-allowance" tabindex="-1">41B. Hyperbaric Allowance <a class="header-anchor" href="#_41b-hyperbaric-allowance" aria-label="Permalink to &quot;41B. Hyperbaric Allowance&quot;">​</a></h1><p><strong>41B.1</strong> From 1 June 2024 an Employee working in, or on call for, a hyperbaric chamber shall be paid the additional allowance at <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>:</p><p><strong>(a)</strong> For each shift in which the Employee undertakes a pressurisation/dive; and</p><p><strong>(b)</strong> In addition to the on-call allowance, for each period of on call where the Employee must comply with restrictions because, in the event of recall, they may be required to undertake a pressurisation/dive.</p><p><strong>41B.2</strong> This allowance is not payable during periods of leave.</p>',5)])])}const b=a(s,[["render",i]]);export{w as __pageData,b as default};
